import{_ as e,o as s,c as a,ac as r}from"./chunks/framework.DnBnwVZk.js";const _=JSON.parse('{"title":"mysql重置密码","description":"","frontmatter":{"date":"2018-11-24T00:00:00.000Z","categories":["Linux"],"tags":["MySQL"],"publish":true},"headers":[],"relativePath":"views/linux/MySQLResetPassword.md","filePath":"views/linux/MySQLResetPassword.md","lastUpdated":1775714960000}'),o={name:"views/linux/MySQLResetPassword.md"};function p(l,t,i,d,n,c){return s(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1543017600000"},[...t[0]||(t[0]=[r('<h1 id="mysql重置密码" tabindex="-1">mysql重置密码 <a class="header-anchor" href="#mysql重置密码" aria-label="Permalink to &quot;mysql重置密码&quot;">​</a></h1><p>参考<a href="https://www.cnblogs.com/activiti/p/7810166.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/activiti/p/7810166.html</a></p><p>操作系统为centos7 x64</p><p>1、修改 /etc/my.cnf，在 [mysqld] 小节下添加一行：skip-grant-tables=1</p><p>这一行配置让 mysqld 启动时不对密码进行验证</p><p>2、重启 mysqld 服务：systemctl restart mysqld</p><p>3、使用 root 用户登录到 mysql：mysql -u root</p><p>4、切换到mysql数据库，更新 user 表：</p><p>update user set authentication_string = password(&#39;root&#39;), password_expired = &#39;N&#39;, password_last_changed = now() where user = &#39;root&#39;;</p><p>在之前的版本中，密码字段的字段名是 password，5.7版本改为了 authentication_string</p><p>5、退出 mysql，编辑 /etc/my.cnf 文件，删除 skip-grant-tables=1 的内容</p><p>6、重启 mysqld 服务，再用新密码登录即可</p><p>另外，MySQL 5.7 在初始安装后（CentOS7 操作系统）会生成随机初始密码，并在 /var/log/mysqld.log 中有记录，可以通过 cat 命令查看，找 password 关键字</p><p>找到密码后，在本机以初始密码登录，并且（也只能）通过 alter user &#39;root&#39;@&#39;localhost&#39; identified by &#39;root&#39; 命令，修改 root 用户的密码为 root，然后退出，重新以root用户和刚设置的密码进行登录即可.</p>',14)])])}const y=e(o,[["render",p]]);export{_ as __pageData,y as default};
